using System.Text.RegularExpressions;

namespace MainDemo.WebAPI.Tests {
    internal static class Utils {
        public static readonly string SamPhoto_String64 = "";
        public static readonly string JohnPhoto_String64 = "";

        public static List<string> ExtractGuids(string jsonString) {
            List<string> guids = new List<string>();
            string pattern = @"([a-z0-9]{8}[-][a-z0-9]{4}[-][a-z0-9]{4}[-][a-z0-9]{4}[-][a-z0-9]{12})";
            MatchCollection mc = Regex.Matches(jsonString, pattern);
            foreach(Match t in mc) {
                guids.Add(t.Value);
            }
            return guids;
        }
    }
}
